import { Component } from '@angular/core';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})
export class AppComponent {
  title = 'advanced-component-demo';

  constructor(private notificationService: NotificationService) { }


  showSuccessNotification(): void {
    this.notificationService.success('Operation completed successfully!');
  }

  showInfoNotification(): void {
    this.notificationService.info('New update available.');
  }

  showWarningNotification(): void {
    this.notificationService.warning('Be careful with this action!');
  }

  showErrorNotification(): void {
    this.notificationService.error('An error occurred, please try again.');
  }

}
